import{_ as e,o as s,c as i,a0 as t}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Subscriptions & Usage Manager","description":"","frontmatter":{},"headers":[],"relativePath":"admin/subscriptions-dashboard.md","filePath":"admin/subscriptions-dashboard.md"}'),o={name:"admin/subscriptions-dashboard.md"};function l(r,a,n,h,p,c){return s(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="subscriptions-usage-manager" tabindex="-1">Subscriptions &amp; Usage Manager <a class="header-anchor" href="#subscriptions-usage-manager" aria-label="Permalink to &quot;Subscriptions &amp; Usage Manager&quot;">​</a></h1><p>This guide is for <code>Supreme Admin</code> users only.</p><p>The <strong>Subscriptions &amp; Usage</strong> page is the platform-wide dashboard for plans, live usage, direct assignments, overrides, and suspension actions.</p><blockquote><p>Screenshot placeholder: <code>subs-admin-overview.png</code> (S61)</p></blockquote><h2 id="what-this-page-shows" tabindex="-1">What this page shows <a class="header-anchor" href="#what-this-page-shows" aria-label="Permalink to &quot;What this page shows&quot;">​</a></h2><p>At the top, the page shows platform summary cards such as:</p><ul><li>total kingdoms</li><li>total alliances</li><li>total plans</li><li>suspended subjects</li><li>warning and critical counts</li></ul><p>Below that, the page gives you:</p><ul><li>search by kingdom or alliance name</li><li>filters by status and plan</li><li>a toggle to open the plans area</li><li>separate usage tables for kingdoms and alliances</li></ul><h2 id="reading-the-usage-tables" tabindex="-1">Reading the usage tables <a class="header-anchor" href="#reading-the-usage-tables" aria-label="Permalink to &quot;Reading the usage tables&quot;">​</a></h2><p>Each row shows:</p><ul><li>the subject name</li><li>its current plan</li><li>the plan source</li><li>top usage warnings</li><li>overall status</li></ul><p>Selecting a row opens its detail area, where you can review:</p><ul><li>per-resource usage bars</li><li>suspension message</li><li>warnings</li><li>cleanup suggestions</li><li>the last calculation time</li></ul><h2 id="what-you-can-do-from-here" tabindex="-1">What you can do from here <a class="header-anchor" href="#what-you-can-do-from-here" aria-label="Permalink to &quot;What you can do from here&quot;">​</a></h2><p>This page is the launch point for three important actions:</p><ul><li><a href="./assign-plans.html">Assign Plans Directly</a></li><li><a href="./suspend-subjects.html">Suspend &amp; Unsuspend</a></li><li>set quota overrides for a specific resource</li></ul><p>It is also the place where you open <a href="./manage-plans.html">Create &amp; Edit Plans</a>.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Use filters first before taking action.</li><li>Open the row detail before suspending or overriding anything.</li><li>Treat direct assignment as an admin shortcut, not as the normal customer-facing request flow.</li></ul>',20)])])}const g=e(o,[["render",l]]);export{d as __pageData,g as default};
